// // This module decodes a 2-bit binary input to a 4-bit one-hot output only when enable is low.
module decoder_2to4(
    input      en,
    input  [1:0] binary_in,

    output reg [3:0] one_hot_out
);

always @(*) begin
    if (en) begin
        case (binary_in)
            2'b00: one_hot_out = 4'b0001;
            2'b01: one_hot_out = 4'b0010;
            2'b10: one_hot_out = 4'b0100;
            2'b11: one_hot_out = 4'b1000;
            default: one_hot_out = 4'b0000;
        endcase
    end else begin
        one_hot_out = 4'b0000;
    end
end

endmodule
